using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&records](auto&& conn) {
        return sqlgen::write(conn, records);
      })
      .value();
}

template<typename T, typename PrimaryKeyType>
void modify_eas_records_by_id_impl(const std::string& primary_key_name,
                                    const PrimaryKeyType& record_id,
                                    const std::string& col_name,
                                    const std::string& new_value) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        // Read the existing record
        auto records = sqlgen::read<std::vector<T>>(conn) | 
                       where(sqlgen::Column(primary_key_name) == record_id);

        if (!records || records->empty()) {
          return sqlgen::Result<void>(std::error_code());
        }

        // Modify the record using reflection
        auto& record = (*records)[0];
        rfl::get_field<rfl::Field>(record, col_name) = new_value;

        // Write back the modified record
        return sqlgen::write(conn, std::vector<T>{record});
      })
      .value();
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
  if (table_name == "Student") {
    modify_eas_records_by_id_impl<Student>(std::string("SNo"), record_id, col_name, new_value);
  } else if (table_name == "Course") {
    modify_eas_records_by_id_impl<Course>(std::string("CID"), static_cast<uint32_t>(std::stoul(record_id)), col_name, new_value);
  } else if (table_name == "Score") {
    modify_eas_records_by_id_impl<Score>(std::string("ScID"), static_cast<uint32_t>(std::stoul(record_id)), col_name, new_value);
  } else if (table_name == "Major") {
    modify_eas_records_by_id_impl<Major>(std::string("MID"), static_cast<uint32_t>(std::stoul(record_id)), col_name, new_value);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        if (table_name == "Student") {
          return sqlgen::remove<Student>(conn) | where("SNo"_c == record_id);
        } else if (table_name == "Course") {
          return sqlgen::remove<Course>(conn) | where("CID"_c == static_cast<uint32_t>(std::stoul(record_id)));
        } else if (table_name == "Score") {
