};


/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn = sqlite::connect("test_db.sqlite");

  // 2. Create tables
  conn.create<Customer>();
  conn.create<Product>();
  conn.create<Order>();
  conn.create<OrderItem>();

  // 3. Query the database with joins to retrieve purchase history
  const auto query = R"(
    SELECT p.name as product_name, o.order_date, oi.quantity
    FROM Customer c
    JOIN "Order" o ON c.customer_id = o.customer_id
    JOIN OrderItem oi ON o.order_id = oi.order_id
    JOIN Product p ON oi.product_id = p.product_id
    WHERE c.customer_id = ?
    ORDER BY o.order_date DESC
  )";

  // 4. Execute query and return results as vector of PurchaseHistory
  auto results = conn.query<PurchaseHistory>(query, customer_id);

  return results;
}

}  // namespace query_customer_purchase_history
