#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_daily_traffic_metrics {

struct PageVisit {
  sqlgen::PrimaryKey<int> visit_id;
  std::string url;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> visit_time;
};

struct DailyTraffic {
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

struct DailyTrafficView {
  static constexpr const char* tablename = "DailyTrafficView";
  static constexpr bool is_view = true;
  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to SQLite database
  auto db = Database("test_db.sqlite");

  // Execute the query to calculate daily traffic metrics
  const std::string query = 
    "SELECT strftime('%Y-%m-%d', visit_time) as visit_date, "
    "COUNT(*) as total_visits, "
    "COUNT(DISTINCT url) as unique_pages "
    "FROM PageVisit "
    "GROUP BY visit_date "
    "ORDER BY visit_date";

  // Execute query and map results to DailyTraffic structure
  auto results = db.query<DailyTraffic>(query);

  return results;
}

}  // namespace query_daily_traffic_metrics
```

This implementation:

1. **Connects to the SQLite database** `test_db.sqlite` using `sqlgen::sqlite::Database`
2. **Executes the SQL query** that:
   - Extracts the date from `visit_time` using `strftime('%Y-%m-%d', visit_time)`
   - Groups results by the extracted date
   - Counts total visits with `COUNT(*)`
   - Counts unique URLs with `COUNT(DISTINCT url)`
   - Orders results by date
3. **Maps the query results** to the `DailyTraffic` struct automatically
4. **Returns** the vector of daily traffic metrics

The sqlgen library handles the ORM mapping between the SQL result columns and the `DailyTraffic` struct fields.

