```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Check if we have any filters
    bool has_filters = filters.title_keyword.has_value() || 
                       filters.min_year.has_value() ||
                       filters.genre.has_value() || 
                       filters.max_price.has_value();

    if (!has_filters) {
        // No filters provided, return all books
        auto result = conn.and_then(read<std::vector<Book>>);
        return result.value_or(std::vector<Book>{});
    }

    // Build dynamic WHERE clause by combining conditions
    auto build_condition = [&]() {
        // Start with an always-true condition
        auto cond = "book_id"_c >= 0;

        // Add LIKE condition for title search
        if (filters.title_keyword.has_value()) {
            std::string pattern = "%" + filters.title_keyword.value() + "%";
            cond = cond && "title"_c.like(pattern);
        }

        // Add >= condition for minimum year
        if (filters.min_year.has_value()) {
            cond = cond && "year"_c >= filters.min_year.value();
        }

        // Add = condition for genre
        if (filters.genre.has_value()) {
            cond = cond && "genre"_c == filters.genre.value();
        }

        // Add <= condition for maximum price
        if (filters.max_price.has_value()) {
            cond = cond && "price"_c <= filters.max_price.value();
        }

        return cond;
    };

    // Execute query with dynamic WHERE clause
    auto result = conn.and_then(read<std::vector<Book>> | where(build_condition()));

    return result.value_or(std::vector<Book>{});
}

}  // namespace query_search_books_by_criteria
```

