namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  try {
    // Begin transaction
    conn->exec("BEGIN TRANSACTION");

    // Deduct from sender account (only if sufficient balance exists)
    auto deduct_stmt = conn->prepare(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?"
    );
    deduct_stmt.bind(amount, from_account_id, amount);
    deduct_stmt.exec();

    // Check if the deduction was successful (row was updated)
    if (conn->changes() == 0) {
      // Insufficient funds or account doesn't exist
      conn->exec("ROLLBACK");
      return false;
    }

    // Add to receiver account
    auto add_stmt = conn->prepare(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?"
    );
    add_stmt.bind(amount, to_account_id);
    add_stmt.exec();

    // Commit the transaction
    conn->exec("COMMIT");
    return true;

  } catch (...) {
    // Rollback on any error
    try {
      conn->exec("ROLLBACK");
    } catch (...) {
      // Ignore rollback errors
    }
    return false;
  }
}

}  // namespace transaction_transfer_funds
