void update_eas_table() {
  design_eas_database_with_major();

  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // 1. Add a new column Grade to Score table with type char(1), not null
        return sqlgen::exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'A';");
      })
      .and_then([](auto&& conn) {
        // 2. Modify the column type of Age in Student table
        // SQLite doesn't support ALTER COLUMN directly, so we need to recreate the table
        // Disable foreign keys temporarily
        return sqlgen::exec(conn, "PRAGMA foreign_keys = OFF;");
      })
      .and_then([](auto&& conn) {
        // Begin transaction
        return sqlgen::exec(conn, "BEGIN TRANSACTION;");
      })
      .and_then([](auto&& conn) {
        // Create new Student table with Age as INTEGER (allowing NULL)
        return sqlgen::exec(conn, 
            "CREATE TABLE Student_new ("
            "SNo VARCHAR(10) PRIMARY KEY, "
            "SName VARCHAR(30), "
            "Sex INT DEFAULT 1, "
            "Birthday DATETIME, "
            "Major INTEGER, "
            "Scorses REAL DEFAULT 0.0, "
            "Remark TEXT, "
            "Age INTEGER);");
      })
      .and_then([](auto&& conn) {
        // Copy data from old table to new table
        return sqlgen::exec(conn, "INSERT INTO Student_new SELECT * FROM Student;");
      })
      .and_then([](auto&& conn) {
        // Drop old Student table
        return sqlgen::exec(conn, "DROP TABLE Student;");
      })
      .and_then([](auto&& conn) {
        // Rename new table to Student
        return sqlgen::exec(conn, "ALTER TABLE Student_new RENAME TO Student;");
      })
      .and_then([](auto&& conn) {
        // Commit transaction
        return sqlgen::exec(conn, "COMMIT;");
      })
      .and_then([](auto&& conn) {
        // Re-enable foreign keys
        return sqlgen::exec(conn, "PRAGMA foreign_keys = ON;");
      })
      .and_then([](auto&& conn) {
        // 3. Drop the Major table
        return sqlgen::exec(conn, "DROP TABLE IF EXISTS Major;");
      })
      .value();
}

} // namespace update_eas_table
