  // 2. Use SELF-JOIN to find mutual friends
  // Find pairs of users who are friends and have mutual connections
  const std::string mutual_friends_query = R"(
    SELECT DISTINCT u1.username as user1_name, u2.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user1_id
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u2.user_id
      )
  )";

  // 3. Use nested query to find users with above-average friend count
  const std::string high_connectivity_query = R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(cnt) 
      FROM (SELECT COUNT(*) as cnt FROM Friendship GROUP BY user1_id)
    )
    ORDER BY friend_count DESC
  )";

  // 4. Find friend-of-friend relationships (not direct friends)
  const std::string fof_query = R"(
    SELECT DISTINCT u1.username as user1_name, u3.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user1_id
    INNER JOIN User u3 ON f2.user_id2 = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3
        WHERE f3.user1_id = u1.user_id AND f3.user2_id = u3.user_id
      )
  )";

  // 5. Count friends per user (aggregation)
  const std::string friend_count_query = R"(
    SELECT u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user1_id
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
  )";

  // Collect results - return friend connections
  std::vector<FriendConnection> results;

  // Execute the main query to get friend connections
  // Using a simple approach: get all direct friendships with usernames
  auto friendship_records = connection.fetch(Select<Friendship>{});

  for (const auto& f : friendship_records) {
    // Get username for user1_id
    auto user1_results = connection.fetch(
      Select<User>{}.where("user_id"_col == f.user1_id)
    );

    // Get username for user2_id
    auto user2_results = connection.fetch(
      Select<User>{}.where("user_id"_col == f.user2_id)
    );

    if (!user1_results.empty() && !user2_results.empty()) {
      results.push_back(FriendConnection{
        .user1_name = user1_results[0].username,
        .user2_name = user2_results[0].username
      });
    }
  }

  return results;
}

}  // namespace analyze_social_network

