#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite").value();

  // Create the OrderItem table if it doesn't exist
  (create_table<OrderItem> | if_not_exists)(conn).value();

  // Insert all order items into the table
  for (const auto& item : items) {
    write(conn, item).value();
  }

  // Perform query with arithmetic calculations to compute business metrics
  auto metrics = (
    select(
      "item_id"_c,
      "order_id"_c,
      "product_id"_c,
      "unit_price"_c,
      "quantity"_c,
      coalesce("discount_rate"_c, 0.0).as("discount_rate"),
      coalesce("tax_rate"_c, 0.0).as("tax_rate"),
      // Calculate gross total: unit_price * quantity
      ("unit_price"_c * "quantity"_c).as("gross_total"),
      // Calculate discounted total: gross_total * (1 - discount_rate/100)
      ("unit_price"_c * "quantity"_c * (1.0 - coalesce("discount_rate"_c, 0.0) / 100.0)).as("discounted_total"),
      // Calculate final total with tax: discounted_total * (1 + tax_rate/100)
      ("unit_price"_c * "quantity"_c * (1.0 - coalesce("discount_rate"_c, 0.0) / 100.0) * (1.0 + coalesce("tax_rate"_c, 0.0) / 100.0)).as("final_total"),
      // Calculate unit cost: unit_price * quantity / quantity = unit_price
      ("unit_price"_c * "quantity"_c / "quantity"_c).as("unit_cost"),
      // Calculate quantity group using modulo operation
      ("quantity"_c % 10).as("quantity_group"),
      // Calculate estimated profit: unit_price * 0.3
      ("unit_price"_c * 0.3).as("estimated_profit")
    ) | from<OrderItem>
      | read<std::vector<OrderMetrics>>
  )(conn).value();

  return metrics;
}

}  // namespace calculate_order_metrics

