# Complete File Contents

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace join_orders_customers_payments {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct Payment {
  sqlgen::PrimaryKey<int> payment_id;
  int order_id;
  double amount;
};

struct Consolidated {
  sqlgen::PrimaryKey<int> order_id;
  std::string customer_name;
  double amount;
};

/**
 * description: join_orders_customers_payments.
 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto conn = sqlite::connect("test_db.sqlite");

  // Build the SQL query with inner joins
  // Join Payment with Order, then with Customer
  // Select order_id, customer name, and payment amount
  // Order by amount in descending order
  const auto sql = R"(
    SELECT o.order_id, c.name as customer_name, p.amount 
    FROM Payment p 
    INNER JOIN "Order" o ON p.order_id = o.order_id 
    INNER JOIN Customer c ON o.customer_id = c.customer_id 
    ORDER BY p.amount DESC
  )";

  // Execute the query and return results mapped to Consolidated struct
  auto results = conn.read<Consolidated>(sql);

  return results;
}

}  // namespace join_orders_customers_payments
```

This implementation:

1. **Connects to the SQLite database** using `sqlgen::sqlite::connect("test_db.sqlite")`
2. **Performs inner joins** across the three tables:
   - Payment → Order (on order_id)
   - Order → Customer (on customer_id)
3. **Selects specific columns**: order_id, customer name (aliased as customer_name), and amount
4. **Orders by amount descending** using `ORDER BY p.amount DESC`
5. **Returns a consolidated dataset** as `std::vector<Consolidated>` using the sqlgen's `read<T>()` method to map SQL results to the struct

The query uses proper table aliases (p, o, c) for clarity and quotes the "Order" table name since it's a SQL reserved keyword.

