#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;
  auto conn = conn_res.value();

  exec(conn, "PRAGMA foreign_keys = ON;");

  exec(conn, "DROP TABLE IF EXISTS Child;");
  exec(conn, "DROP TABLE IF EXISTS Parent;");

  exec(conn, "CREATE TABLE Parent (parent_id INTEGER PRIMARY KEY, name TEXT NOT NULL);");
  exec(conn, "CREATE TABLE Child (child_id INTEGER PRIMARY KEY, parent_id INTEGER NOT NULL REFERENCES Parent(parent_id) ON DELETE CASCADE, note TEXT NOT NULL);");

  auto parent = Parent{.parent_id = 1, .name = "Parent 1"};
  auto children = std::vector<Child>{
      {.child_id = 1, .parent_id = 1, .note = "Child 1"},
      {.child_id = 2, .parent_id = 1, .note = "Child 2"}
  };

  insert(conn, parent);
  insert(conn, children);

  auto res = (delete_from<Parent> | where("parent_id"_c == 1))(conn);
  if (!res) return false;

  auto remaining_children = sqlgen::read<std::vector<Child>>(conn);
  if (!remaining_children) return false;

  return remaining_children.value().empty();
}

}  // namespace cascade_delete_demo

