```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Enable foreign key constraints (required for SQLite cascade delete)
  conn.execute("PRAGMA foreign_keys = ON");

  // Drop tables if they exist to ensure clean state
  conn.execute("DROP TABLE IF EXISTS Child");
  conn.execute("DROP TABLE IF EXISTS Parent");

  // Create tables (Parent first, then Child due to foreign key dependency)
  conn.create_table<Parent>();
  conn.create_table<Child>();

  // Insert parent record
  Parent parent{.parent_id = 1, .name = "Parent1"};
  conn.insert(parent);

  // Insert child records with same parent_id
  Child child1{.child_id = 1, .parent_id = 1, .note = "Child1"};
  Child child2{.child_id = 2, .parent_id = 1, .note = "Child2"};
  conn.insert(child1);
  conn.insert(child2);

  // Verify children exist before deletion
  auto children_before = conn.select<Child>().execute();
  size_t count_before = children_before.size();

  // Delete parent record
  conn.execute("DELETE FROM Parent WHERE parent_id = 1");

  // Verify children are deleted automatically due to cascade
  auto children_after = conn.select<Child>().execute();
  size_t count_after = children_after.size();

  // Return true if cascade delete worked correctly
  // (2 children existed before, 0 children exist after parent deletion)
  return count_before == 2 && count_after == 0;
}

}  // namespace cascade_delete_demo
```

