```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Since SQLite doesn't support FULL OUTER JOIN natively,
  // we simulate it using UNION of LEFT JOIN and unmatched right rows
  const std::string full_join_query = R"(
    SELECT COALESCE(s.name, '') as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION ALL
    SELECT COALESCE(s.name, '') as supplier_name, p.name as product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  // Connect to the database and execute the query
  auto results = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(sqlgen::query<std::vector<SupProd>>(full_join_query));

  // Return results or empty vector if operation failed
  if (results) {
    return *results;
  }

  return std::vector<SupProd>{};
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the SQLite database** "test_db.sqlite" using `sqlgen::sqlite::connect()`
2. **Simulates FULL OUTER JOIN** since SQLite doesn't natively support it by using:
   - A LEFT JOIN from Supplier to Product (gets all suppliers with their products, if any)
   - UNION ALL with a LEFT JOIN from Product to Supplier WHERE supplier_id IS NULL (gets products without suppliers)
3. **Uses COALESCE** to handle NULL supplier names (converts them to empty strings since `supplier_name` is not optional in the struct)
4. **Returns the joined results** as a `std::vector<SupProd>`
5. **Handles errors gracefully** by returning an empty vector if the database operation fails

The query ensures all suppliers and all products are included in the results, with NULL values represented as `std::nullopt` for optional fields.

