```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_department_employees {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string department_name;
  std::string location;
};

struct Employee {
  sqlgen::PrimaryKey<int> employee_id;
  int department_id;
  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to the SQLite database and set up tables
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create tables and insert data
  conn.and_then(create_table<Department> | if_not_exists)
      .and_then(write(depts))
      .and_then(create_table<Employee> | if_not_exists)
      .and_then(write(emps));

  // INNER JOIN: Get employees with assigned departments
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Department d INNER JOIN Employee e ON d.department_id = e.department_id
  auto inner_join_result = conn.and_then(
    []() {
      return sqlgen::query(R"(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Department d
        INNER JOIN Employee e ON d.department_id = e.department_id
      )") | read<std::vector<JoinResult>>;
    }
  );

  if (inner_join_result) {
    analysis.inner_join_results = inner_join_result.value();
  }

  // LEFT JOIN: Include all employees (even without departments)
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Employee e LEFT JOIN Department d ON e.department_id = d.department_id
  auto left_join_result = conn.and_then(
    []() {
      return sqlgen::query(R"(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Employee e
        LEFT JOIN Department d ON e.department_id = d.department_id
      )") | read<std::vector<JoinResult>>;
    }
  );

  if (left_join_result) {
    analysis.left_join_results = left_join_result.value();
  }

  // RIGHT JOIN: Include all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN directly, so we use LEFT JOIN with reversed tables
  // SELECT d.department_name, e.first_name, e.last_name, e.salary
  // FROM Department d LEFT JOIN Employee e ON d.department_id = e.department_id
  auto right_join_result = conn.and_then(
    []() {
      return sqlgen::query(R"(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Department d
        LEFT JOIN Employee e ON d.department_id = e.department_id
      )") | read<std::vector<JoinResult>>;
    }
  );

  if (right_join_result) {
    analysis.right_join_results = right_join_result.value();
  }

  // FULL JOIN: Include all employees and departments
  // SQLite doesn't support FULL OUTER JOIN, so we use UNION of LEFT joins
  auto full_join_result = conn.and_then(
    []() {
      return sqlgen::query(R"(
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Employee e
        LEFT JOIN Department d ON e.department_id = d.department_id
        UNION
        SELECT d.department_name, e.first_name, e.last_name, e.salary
        FROM Department d
        LEFT JOIN Employee e ON d.department_id = e.department_id
        WHERE e.employee_id IS NULL
      )") | read<std::vector<JoinResult>>;
    }
  );

  if (full_join_result) {
    analysis.full_join_results = full_join_result.value();
  }

  return analysis;
}

}  // namespace analyze_department_employees
```

This implementation:

1. **Connects to the SQLite database** (`test_db.sqlite`)
2. **Creates tables** for Department and Employee if they don't exist
3. **Inserts data** from the provided vectors
4. **Performs INNER JOIN** to get employees with matching departments
5. **Performs LEFT JOIN** starting from Employee table to include all employees
6. **Performs RIGHT JOIN** (simulated via LEFT JOIN with reversed tables since SQLite doesn't support RIGHT JOIN)
7. **Performs FULL JOIN** (simulated via UNION since SQLite doesn't support FULL OUTER JOIN)
8. **Returns comprehensive analysis** with all join results

The function uses `std::optional` fields in `JoinResult` to handle NULL values that may appear in outer joins.

