#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([limit_count](auto db) {
      // Perform JOIN between Product and Sales tables
      // Calculate total sales (price * quantity) for each product
      // Group by product details, order by total sales descending, and limit results
      return db.template execute<std::vector<TopProduct>>(
        select(
          col<Product>("product_id"_c),
          col<Product>("product_name"_c),
          col<Product>("category"_c),
          sum(col<Product>("price"_c) * col<Sales>("quantity"_c)).as("total_sales"_c)
        ) |
        from<Product>() |
        inner_join<Sales>(col<Product>("product_id"_c) == col<Sales>("product_id"_c)) |
        group_by(col<Product>("product_id"_c), col<Product>("product_name"_c), col<Product>("category"_c)) |
        order_by(desc("total_sales"_c)) |
        limit(limit_count)
      );
    });

  if (result) {
    return result.value();
  }

  return std::vector<TopProduct>{};
}

}  // namespace get_top_products
