# Complete File Contents

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // Execute query to extract weekday and aggregate totals
  // SQLite's strftime('%w', datetime) extracts day of week (0-6, where 0=Sunday)
  // Group by weekday and sum quantities
  const auto results = db.exec<WeekdayStats>(R"(
    SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday, 
           SUM(quantity) as total_quantity
    FROM Sales
    GROUP BY strftime('%w', sale_time)
    ORDER BY weekday
  )");

  return results;
}

}  // namespace weekday_sales_analysis
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::Database` to connect to "test_db.sqlite"

2. **Weekday Extraction**: Uses SQLite's `strftime('%w', sale_time)` function which returns:
   - 0 = Sunday
   - 1 = Monday
   - 2 = Tuesday
   - 3 = Wednesday
   - 4 = Thursday
   - 5 = Friday
   - 6 = Saturday

3. **Aggregation**: Uses `SUM(quantity)` grouped by weekday to calculate total quantity sold per day of the week

4. **Query Execution**: Uses `db.exec<WeekdayStats>()` to execute the raw SQL query and automatically map results to the `WeekdayStats` structure

5. **Ordering**: Results are ordered by weekday for consistent output

