# Complete File Implementation

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;

  // Connect to the SQLite database
  auto session = Session("test_db.sqlite");

  // Build SQL query with temporal operations for SQLite
  // SQLite uses strftime for date/time extraction and julianday for date differences
  const std::string query = R"(
    SELECT p.project_id, p.name,
           CAST(strftime('%d', t.start_time) AS INTEGER) as day,
           CAST(strftime('%m', t.start_time) AS INTEGER) as month,
           CAST(strftime('%Y', t.start_time) AS INTEGER) as year,
           CAST(strftime('%H', t.start_time) AS INTEGER) as hour,
           CAST(strftime('%M', t.start_time) AS INTEGER) as minute,
           CAST(strftime('%S', t.start_time) AS INTEGER) as second,
           (julianday(t.end_time) - julianday(t.start_time)) as duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
  )";

  // Execute query and return results mapped to TimeMetrics struct
  return session.query<TimeMetrics>(query);
}

}  // namespace project_time_tracking
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::Session` to connect to "test_db.sqlite"

2. **SQLite Temporal Functions**:
   - `strftime('%d', t.start_time)` - extracts day (01-31)
   - `strftime('%m', t.start_time)` - extracts month (01-12)
   - `strftime('%Y', t.start_time)` - extracts year
   - `strftime('%H', t.start_time)` - extracts hour (00-23)
   - `strftime('%M', t.start_time)` - extracts minute (00-59)
   - `strftime('%S', t.start_time)` - extracts second (00-59)
   - `julianday(end_time) - julianday(start_time)` - calculates days between timestamps

3. **JOIN Operation**: Performs INNER JOIN between Project and TimeLog tables on project_id

4. **Type Casting**: Uses CAST to ensure integer types for date/time components

5. **Result Mapping**: The sqlgen library automatically maps query results to the `TimeMetrics` struct based on column names

