```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // Query to group posts per user with aggregations
  // JOIN User and Post tables, GROUP BY user, compute COUNT and AVG(length(content))
  auto results = db.query<Stats>(
    R"(
      SELECT u.user_id, u.name, 
             COUNT(p.post_id) as post_count, 
             AVG(LENGTH(p.content)) as avg_length
      FROM User u
      LEFT JOIN Post p ON u.user_id = p.user_id
      GROUP BY u.user_id, u.name
    )"
  );

  return results;
}

}  // namespace group_by_with_aggregations
```

This implementation:
1. **Connects to the database**: Opens "test_db.sqlite" using `sqlgen::sqlite::Database`
2. **Joins tables**: Uses `LEFT JOIN` to join User and Post tables on `user_id`
3. **Groups by user**: Uses `GROUP BY u.user_id, u.name` to group posts per user
4. **Computes aggregations**: 
   - `COUNT(p.post_id)` for the number of posts per user
   - `AVG(LENGTH(p.content))` for the average content length
5. **Returns results**: Maps the query results to `Stats` struct and returns as a vector

The `LEFT JOIN` ensures all users are included even if they have no posts, and `avg_length` is `std::optional<double>` to handle null values when a user has no posts.

